+  // Handle umax(shl nuw X, 1, add X, 1) -> select(icmp eq X, 0, 1, shl X, 1)
+  //
+  // This is valid because:
+  // - For x = 0: x * 2 = 0 < 1 = x + 1, so umax = 1
+  // - For x >= 1: x * 2 >= x + 1 (since x - 1 >= 0), so umax = x * 2
+  // The nuw flag ensures no overflow in the shift.
+  if (IID == Intrinsic::umax) {
+    Value *Op0 = II->getArgOperand(0);
+    Value *Op1 = II->getArgOperand(1);
+    Value *X;
+
+    // Try matching umax(shl nuw X, 1, add X, 1) or umax(add X, 1, shl nuw X, 1)
+    auto matchPattern = [&](Value *Mul, Value *Add) -> Instruction * {
+      if (match(Mul, m_Shl(m_Value(X), m_One())) &&
+          match(Add, m_Add(m_Specific(X), m_One()))) {
+        auto *BO = dyn_cast<BinaryOperator>(Mul);
+        if (BO && BO->hasNoUnsignedWrap()) {
+          Value *IsZero = Builder.CreateICmpEQ(
+              X, ConstantInt::get(X->getType(), 0));
+          Instruction *Sel = cast<Instruction>(Builder.CreateSelect(
+              IsZero, ConstantInt::get(II->getType(), 1), Mul));
+
+          // Add range metadata [1, 0) meaning the result is always >= 1.
+          // This helps subsequent passes compute the function's return range.
+          Metadata *LoAndHi[] = {
+              ConstantAsMetadata::get(ConstantInt::get(II->getType(), 1)),
+              ConstantAsMetadata::get(ConstantInt::get(II->getType(), 0))};
+          Sel->setMetadata(LLVMContext::MD_range,
+                           MDNode::get(Builder.getContext(), LoAndHi));
+
+          return replaceInstUsesWith(CI, Sel);
+        }
+      }
+      return nullptr;
+    };
+
+    if (Instruction *Res = matchPattern(Op0, Op1))
+      return Res;
+    if (Instruction *Res = matchPattern(Op1, Op0))
+      return Res;
+  }
+
   // Try to fold intrinsic into select operands. This is legal if:
   //  * The intrinsic is speculatable.
   //  * The select condition is not a vector, or the intrinsic does not
@@ -3768,6 +3811,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
